The `tabItem()` modifier is deprecated. Use the `Tab` view API instead:

```swift
TabView {
    Tab("Home", systemImage: "house") {
        HomeView()
    }
    Tab("Search", systemImage: "magnifyingglass") {
        SearchView()
    }
}
```

Use a type-safe enum instead of integers:

```swift
enum AppTab { case home, search, profile }
@State private var selectedTab = AppTab.home

TabView(selection: $selectedTab) {
    Tab("Home", systemImage: "house", value: .home) { HomeView() }
    Tab("Search", systemImage: "magnifyingglass", value: .search) { SearchView() }
}
```

Use `NavigationStack` with value-based `NavigationLink` and `navigationDestination(for:)`:

```swift
NavigationStack {
    List(items) { item in
        NavigationLink(item.name, value: item)
    }
    .navigationDestination(for: Item.self) { item in
        DetailView(item: item)
    }
}
```

`NavigationView` is deprecated. Do not mix `NavigationLink(destination:)` and `navigationDestination(for:)`.

Use `.topBarTrailing`:

```swift
.toolbar {
    ToolbarItem(placement: .topBarTrailing) {
        Button("Edit", action: editAction)
    }
}
```

Use text interpolation with individually styled `Text` values:

```swift
var body: some View {
    let hello = Text("Hello").foregroundStyle(.red)
    let world = Text("World").foregroundStyle(.blue)
    Text("\(hello) \(world)")
}
```

Use the `@Observable` macro. The `ObservableObject`/`@Published`/`@EnvironmentObject` pattern is legacy:

```swift
@Observable
@MainActor
class ShoppingCart {
    var items: [Item] = []
    var total: Double = 0
}

// Owner
@State private var cart = ShoppingCart()
var body: some View {
    ChildView().environment(cart)
}

// Consumer
@Environment(ShoppingCart.self) private var cart
```

Yes. `@Observable` classes must be marked `@MainActor` to ensure properties are accessed on the main thread for safe UI updates. Exception: projects using Main Actor default actor isolation (Swift 6 build setting).

```swift
@Observable
@MainActor
class UserSettings {
    var theme: Theme = .system
}
```

Avoid inline `Binding(get:set:)` — it's fragile. Use a standard binding from `@State` with `onChange()`:

```swift
@State private var username = ""

var body: some View {
    TextField("Username", text: $username)
        .onChange(of: username) {
            model.save()
        }
}
```

Use `ContentUnavailableView.search`, which reads the search term from the `searchable()` context automatically:

```swift
.overlay {
    if results.isEmpty {
        ContentUnavailableView.search
    }
}
```

No need to pass the search text manually.

Use `onChange` with either the 0-parameter or 2-parameter variant:

```swift
// 0-parameter: just react
.onChange(of: searchText) {
    performSearch()
}

// 2-parameter: access old and new
.onChange(of: searchText) { oldValue, newValue in
    if newValue.count > oldValue.count { showSuggestions() }
}
```

Use the `completion` closure on `withAnimation()`:

```swift
withAnimation {
    scale = 2
} completion: {
    withAnimation {
        scale = 1
    }
}
```

Use the `@Animatable` macro:

```swift
@Animatable
struct PieSlice: Shape {
    var endAngle: Double

    func path(in rect: CGRect) -> Path { /* draw using endAngle */ }
}
```

Mark non-animatable properties with `@AnimatableIgnored`.

Use `LabeledContent`:

```swift
Form {
    LabeledContent("Volume") {
        Slider(value: $volume, in: 0...100)
    }
}
```

Attach to the specific element that triggers it. In iOS 26, the dialog animates from its source element (Liquid Glass):

```swift
Button("Delete", role: .destructive) {
    showDeleteConfirmation = true
}
.confirmationDialog("Are you sure?", isPresented: $showDeleteConfirmation) {
    Button("Delete", role: .destructive, action: deleteItem)
}
```

`VStack` renders all 500 items immediately. Use `LazyVStack`:

```swift
ScrollView {
    LazyVStack {
        ForEach(items) { item in
            ItemRow(item: item)
        }
    }
}
```

Only use eager `VStack` for small, fixed numbers of children.

View initializers should be trivial. Move work to `.task()`:

```swift
struct ItemListView: View {
    @State private var items: [Item] = []

    var body: some View {
        List(items) { item in Text(item.name) }
            .task { items = try? await fetchAndSort() }
    }
}
```

SwiftUI may recreate views frequently, repeating expensive init work.

Use `@ViewBuilder`:

```swift
@ViewBuilder
func makeView(isRed: Bool) -> some View {
    if isRed {
        Text("Red").foregroundStyle(.red)
    } else {
        Text("Blue").foregroundStyle(.blue)
    }
}
```

Or extract into a separate `View` struct.

Extract into separate `View` structs, each in its own file:

```swift
// HeaderView.swift
struct HeaderView: View {
    var body: some View { /* header content */ }
}
```

Computed properties and methods don't get the same SwiftUI optimization as dedicated `View` structs.

Use the `@Entry` macro:

```swift
extension EnvironmentValues {
    @Entry var accentTheme: Theme = .default
}
```

This replaces the old boilerplate of creating an `EnvironmentKey` struct. Also works for `FocusValues`, `Transaction`, and `ContainerValues`.

Use `async`/`await` with `@MainActor`:

```swift
func fetchData() async {
    let data = await networkService.load()
    await MainActor.run { self.items = data }
}
```

Or mark the property/class as `@MainActor` so updates happen automatically.

Use an `actor`:

```swift
actor Cache {
    private var store: [String: Data] = [:]

    func get(_ key: String) -> Data? { store[key] }
    func set(_ key: String, data: Data) { store[key] = data }
}
```

Actors provide compile-time data race protection.

Conform your type to `Identifiable`:

```swift
struct Item: Identifiable {
    let id = UUID()
    var name: String
}

ForEach(items) { item in Text(item.name) }
```

iOS 26 has a native `WebView`:

```swift
import WebKit

struct BrowserView: View {
    var body: some View {
        WebView(url: URL(string: "https://example.com")!)
    }
}
```

Use `ImageRenderer`:

```swift
let renderer = ImageRenderer(content: MyView())
if let image = renderer.uiImage {
    // use the UIImage
}
```

Yes. All CloudKit-synced SwiftData relationships must be optional, and all properties must have defaults:

```swift
@Model
class Article {
    var title: String = ""
    var tags: [Tag]? // Must be optional for CloudKit
}
```

Use `PersonNameComponents` — name order varies by culture:

```swift
var name: PersonNameComponents {
    var c = PersonNameComponents()
    c.givenName = firstName
    c.familyName = lastName
    return c
}

Text(name.formatted(.name(style: .long)))
```

No. `@State` is private and owned by one view. Pass a binding:

```swift
// Parent
@State private var count = 0
var body: some View { ChildView(count: $count) }

// Child
struct ChildView: View {
    @Binding var count: Int
}
```

If the child only reads, pass the value as `let`.

Use the `#Preview` macro:

```swift
#Preview {
    ContentView()
}

#Preview("Dark Mode") {
    ContentView()
        .preferredColorScheme(.dark)
}
```

Color alone isn't sufficient. Check `accessibilityDifferentiateWithoutColor` and provide secondary indicators:

```swift
@Environment(\.accessibilityDifferentiateWithoutColor) private var differentiateWithoutColor

HStack {
    Circle().fill(statusColor).frame(width: 12, height: 12)
    if differentiateWithoutColor {
        Image(systemName: statusIcon)
    }
    Text(statusLabel)
}
```

Store the built view value instead of an escaping closure:

```swift
struct CardView<Content: View>: View {
    @ViewBuilder let content: Content

    var body: some View {
        VStack(alignment: .leading) { content }
            .padding()
            .background(.ultraThinMaterial)
            .clipShape(.rect(cornerRadius: 8))
    }
}
```

Errors from user actions must be surfaced to the user, not silently swallowed:

```swift
@State private var errorMessage: String?
@State private var showError = false

func save() {
    do { try dataStore.save() }
    catch {
        errorMessage = error.localizedDescription
        showError = true
    }
}

// In body:
.alert("Save Failed", isPresented: $showError) { }
    message: { Text(errorMessage ?? "Unknown error") }
```

`print()` in a catch is only appropriate for development debugging.

You need to explicitly `import Combine`. It's no longer provided implicitly through SwiftUI:

```swift
import SwiftUI
import Combine

class SearchDebouncer: ObservableObject {
    @Published var searchText = ""
    // Combine publisher setup...
}
```

Note: `ObservableObject` is legacy but is still appropriate when you need Combine publishers for debouncing.

No. SwiftUI does not cache view body evaluations. The `body` property is re-evaluated on every state change. Expensive work like parsing, sorting, or network calls should be in `.task()` or your data model layer:

```swift
@State private var items: [Item] = []

var body: some View {
    List(items) { item in Text(item.name) }
        .task { items = try? await parseAndLoad() }
}
```

Button action closures are synchronous. Wrap async calls in `Task`:

```swift
Button("Load") {
    Task {
        await loadData()
    }
}
```

For async work tied to state changes, prefer `.task()` with a trigger value. Avoid creating tasks in `body` or `init`.
